import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function AdminPanel() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [users, setUsers] = useState([]);
  const [reports, setReports] = useState([]);
  const [tab, setTab] = useState('users');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user || user.role !== 'admin') { navigate('/'); return; }
    Promise.all([
      api.get('/users'),
      api.get('/users/admin/reports')
    ]).then(([u, r]) => {
      setUsers(u.data);
      setReports(r.data);
    }).catch(() => {})
    .finally(() => setLoading(false));
  }, [user]);

  const handleBlock = async (userId, block) => {
    try {
      await api.post(`/users/${userId}/${block ? 'block' : 'unblock'}`);
      setUsers(prev => prev.map(u => u.id === userId ? { ...u, is_blocked: block } : u));
    } catch (err) {
      alert(err.response?.data?.error || 'ą×čłąĖą▒ą║ą░');
    }
  };

  const handleDeleteTask = async (taskId) => {
    if (!window.confirm('ąŻą┤ą░ą╗ąĖčéčī ąĘą░ą┤ą░čćčā?')) return;
    try {
      await api.delete(`/tasks/${taskId}`);
      alert('ąŚą░ą┤ą░čćą░ čāą┤ą░ą╗ąĄąĮą░');
    } catch (err) {
      alert(err.response?.data?.error || 'ą×čłąĖą▒ą║ą░');
    }
  };

  return (
    <div className="app-container">
      <div className="page-header">
        <button className="back-btn" onClick={() => navigate('/')}>ŌåÉ ąØą░ąĘą░ą┤</button>
        <span className="page-title">­¤øĪ’ĖÅ Admin Panel</span>
      </div>

      {/* Tabs */}
      <div style={{
        display: 'flex', background: 'white', borderBottom: '1px solid var(--border)'
      }}>
        {['users', 'reports'].map(t => (
          <button
            key={t}
            onClick={() => setTab(t)}
            style={{
              flex: 1, padding: '12px', border: 'none', background: 'none',
              fontWeight: 700, fontSize: 14, cursor: 'pointer',
              borderBottom: tab === t ? '3px solid var(--green)' : '3px solid transparent',
              color: tab === t ? 'var(--green)' : 'var(--text-muted)'
            }}
          >
            {t === 'users' ? `­¤æź ą¤ąŠą╗čīąĘąŠą▓ą░čéąĄą╗ąĖ (${users.length})` : `­¤Ü® ą¢ą░ą╗ąŠą▒čŗ (${reports.length})`}
          </button>
        ))}
      </div>

      <div style={{ padding: '16px 16px 40px' }}>
        {loading && <div className="loading"><div className="spinner" /></div>}

        {/* Users tab */}
        {!loading && tab === 'users' && users.map(u => (
          <div key={u.id} className="card" style={{ marginBottom: 10 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{
                width: 42, height: 42, borderRadius: '50%',
                background: u.is_blocked ? '#fee2e2' : 'var(--green-pale)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontWeight: 700, color: u.is_blocked ? '#dc2626' : 'var(--green)'
              }}>
                {u.username?.[0]?.toUpperCase()}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700 }}>{u.username}</div>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{u.email}</div>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                  ŌŁÉ {u.rating} ┬Ę {u.role}
                  {u.is_blocked && <span style={{ color: '#dc2626', marginLeft: 6 }}>­¤Ü½ ąŚą░ą▒ą╗ąŠą║ąĖčĆąŠą▓ą░ąĮ</span>}
                </div>
              </div>
              {u.role !== 'admin' && (
                <button
                  onClick={() => handleBlock(u.id, !u.is_blocked)}
                  style={{
                    background: u.is_blocked ? 'var(--green)' : '#fee2e2',
                    color: u.is_blocked ? 'white' : '#dc2626',
                    border: 'none', borderRadius: 8, padding: '6px 12px',
                    fontSize: 12, fontWeight: 700, cursor: 'pointer'
                  }}
                >
                  {u.is_blocked ? 'ąĀą░ąĘą▒ą╗ąŠą║' : 'ąæą╗ąŠą║'}
                </button>
              )}
            </div>
          </div>
        ))}

        {/* Reports tab */}
        {!loading && tab === 'reports' && (
          reports.length === 0 ? (
            <div style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '40px 0' }}>
              ą¢ą░ą╗ąŠą▒ ąĮąĄčé ­¤Äē
            </div>
          ) : (
            reports.map(r => (
              <div key={r.id} className="card" style={{ marginBottom: 10 }}>
                <div style={{ fontWeight: 700, marginBottom: 6, color: '#dc2626' }}>
                  ­¤Ü® {r.reporter_name} ŌåÆ {r.reported_name}
                </div>
                <p style={{ fontSize: 14, color: 'var(--text-muted)', marginBottom: 8 }}>{r.reason}</p>
                <div style={{ fontSize: 12, color: 'var(--text-muted)', display: 'flex', gap: 12 }}>
                  <span>{new Date(r.created_at).toLocaleDateString('ru-RU')}</span>
                  <span>ąĪčéą░čéčāčü: {r.status}</span>
                </div>
                {r.task_id && (
                  <button
                    onClick={() => handleDeleteTask(r.task_id)}
                    style={{
                      marginTop: 8, background: '#fee2e2', color: '#dc2626',
                      border: 'none', borderRadius: 8, padding: '6px 12px',
                      fontSize: 12, fontWeight: 700, cursor: 'pointer'
                    }}
                  >
                    ­¤Śæ’ĖÅ ąŻą┤ą░ą╗ąĖčéčī ąĘą░ą┤ą░čćčā #{r.task_id}
                  </button>
                )}
              </div>
            ))
          )
        )}
      </div>
    </div>
  );
}
